+        // initializations
+        for (int k = 0; k < cols; ++k) {
+            permutation[k] = k;
+            double norm2 = 0;
+            for (int i = 0; i < jacobian.length; ++i) {
+                double akk = jacobian[i][k];
+                norm2 += akk * akk;
+            }
+            jacNorm[k] = Math.sqrt(norm2);
